import anthropic
import time
import logging
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional

logger = logging.getLogger("fallback_client")

class CircuitState(Enum):
    CLOSED = "closed"     # normal operation
    OPEN = "open"         # failing, skip this tier
    HALF_OPEN = "half_open"  # testing if recovered

@dataclass
class CircuitBreaker:
    failure_threshold: int = 3
    recovery_timeout: float = 60.0  # seconds

    failures: int = 0
    last_failure_time: float = 0.0
    state: CircuitState = CircuitState.CLOSED

    def record_success(self):
        self.failures = 0
        self.state = CircuitState.CLOSED

    def record_failure(self):
        self.failures += 1
        self.last_failure_time = time.time()
        if self.failures >= self.failure_threshold:
            self.state = CircuitState.OPEN
            logger.warning("Circuit opened after %d failures", self.failures)

    def is_available(self) -> bool:
        if self.state == CircuitState.CLOSED:
            return True
        if self.state == CircuitState.OPEN:
            if time.time() - self.last_failure_time > self.recovery_timeout:
                self.state = CircuitState.HALF_OPEN
                return True  # allow one test request
            return False
        return True  # HALF_OPEN: allow test

@dataclass
class ModelTier:
    model: str
    base_url: Optional[str] = None
    timeout: float = 30.0
    circuit: CircuitBreaker = field(default_factory=CircuitBreaker)

class FallbackClient:
    """Drop-in replacement for anthropic.Anthropic() with automatic failover."""

    DEFAULT_TIERS = [
        ModelTier("claude-opus-4-5", timeout=30.0),
        ModelTier("claude-opus-4-5", base_url="https://api.anthropic-eu.com",
                  timeout=30.0),  # hypothetical EU endpoint
        ModelTier("claude-sonnet-4-5", timeout=20.0),
    ]

    def __init__(self, tiers: Optional[list] = None, api_key: Optional[str] = None):
        self.tiers = tiers or self.DEFAULT_TIERS
        self._api_key = api_key

    def _client(self, tier: ModelTier) -> anthropic.Anthropic:
        kwargs = {}
        if tier.base_url:
            kwargs["base_url"] = tier.base_url
        if self._api_key:
            kwargs["api_key"] = self._api_key
        return anthropic.Anthropic(**kwargs)

    def create_message(self, *, model: Optional[str] = None, **kwargs):
        """
        Try each tier in order. Return the first successful response.
        model parameter is ignored if set; tier determines the model.
        """
        last_error = None
        for tier in self.tiers:
            if not tier.circuit.is_available():
                logger.info("Skipping tier %s (circuit open)", tier.model)
                continue

            try:
                client = self._client(tier)
                response = client.messages.create(
                    model=tier.model,
                    timeout=tier.timeout,
                    **kwargs
                )
                tier.circuit.record_success()
                logger.info("Request served by %s", tier.model)
                return response

            except anthropic.RateLimitError as e:
                tier.circuit.record_failure()
                last_error = e
                logger.warning("Rate limit on %s, trying next tier", tier.model)

            except anthropic.APIStatusError as e:
                if e.status_code >= 500:
                    tier.circuit.record_failure()
                    last_error = e
                    logger.warning("Server error %d on %s", e.status_code, tier.model)
                else:
                    raise  # 4xx errors are client errors; don't fallback

            except (TimeoutError, anthropic.APIConnectionError) as e:
                tier.circuit.record_failure()
                last_error = e
                logger.warning("Connection/timeout on %s", tier.model)

        raise RuntimeError(f"All tiers exhausted. Last error: {last_error}") from last_error

# Usage:
# client = FallbackClient()
# response = client.create_message(max_tokens=1024, messages=[...])

import time
from dataclasses import dataclass, field
from collections import deque

@dataclass
class FallbackMetrics:
    """Rolling window metrics for fallback monitoring."""
    window_seconds: float = 300.0  # 5-minute window
    events: deque = field(default_factory=deque)

    def record(self, tier_used: int, total_tiers: int, latency_ms: float):
        now = time.time()
        self.events.append({
            "time": now,
            "tier": tier_used,
            "latency_ms": latency_ms,
            "was_fallback": tier_used > 0
        })
        # Prune old events
        cutoff = now - self.window_seconds
        while self.events and self.events[0]["time"] < cutoff:
            self.events.popleft()

    def summary(self) -> dict:
        if not self.events:
            return {"requests": 0, "fallback_rate": 0.0, "p99_latency_ms": 0.0}
        total = len(self.events)
        fallbacks = sum(1 for e in self.events if e["was_fallback"])
        latencies = sorted(e["latency_ms"] for e in self.events)
        p99_idx = int(len(latencies) * 0.99)
        return {
            "requests": total,
            "fallback_rate": fallbacks / total,
            "p99_latency_ms": latencies[min(p99_idx, len(latencies)-1)],
            "tier_distribution": {
                str(tier): sum(1 for e in self.events if e["tier"] == tier)
                for tier in set(e["tier"] for e in self.events)
            }
        }

    def should_alert(self) -> tuple[bool, str]:
        summary = self.summary()
        if summary["fallback_rate"] > 0.05:  # >5% fallback rate
            return True, f"High fallback rate: {summary['fallback_rate']:.1%}"
        if summary["p99_latency_ms"] > 10000:  # p99 > 10s
            return True, f"High p99 latency: {summary['p99_latency_ms']:.0f}ms"
        return False, ""
